import React, { useState, useEffect } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';

const HomePage = () => {
  const theme = useTheme();
  const [currentExample, setCurrentExample] = useState(0);
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  // Dynamic testimonial examples
  const examples = [
    {
      industry: "Life Coaching",
      original: "The coaching was good. I learned some things that helped me.",
      enhanced: "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.",
      client: "Michael T.",
      avatar: "M"
    },
    {
      industry: "Web Design",
      original: "They built a nice website for me. It works well.",
      enhanced: "The team at DesignPro delivered beyond my expectations. My new website has increased conversions by 43% in the first month alone. Their attention to detail and strategic approach to UX completely transformed my online presence.",
      client: "Jessica K.",
      avatar: "J"
    },
    {
      industry: "Fitness Training",
      original: "Good trainer. I lost some weight and feel better.",
      enhanced: "After 3 months with Alex, I've lost 28 pounds and completely transformed my relationship with fitness. His personalized approach addressed my specific challenges, and for the first time in my life, I actually look forward to my workouts!",
      client: "David R.",
      avatar: "D"
    }
  ];

  // Auto-rotate examples
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentExample((prev) => (prev + 1) % examples.length);
    }, 8000);
    return () => clearInterval(interval);
  }, [examples.length]);

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{
          pt: { xs: 10, md: 16 },
          pb: { xs: 12, md: 18 },
          position: 'relative',
        }}
      >
        {/* Background gradient */}
        <Box 
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'linear-gradient(180deg, rgba(93, 95, 239, 0.05) 0%, rgba(93, 95, 239, 0) 100%)',
            zIndex: -1
          }}
        />

        <Container maxWidth="lg">
          <Grid container spacing={6} alignItems="center">
            <Grid item xs={12} md={6}>
              <Chip
                icon={<AutoAwesomeIcon />}
                label="AI-Powered Testimonials"
                sx={{ 
                  mb: 3, 
                  bgcolor: 'primary.light', 
                  color: 'primary.dark',
                  fontWeight: 600,
                  '& .MuiChip-icon': { color: 'primary.main' }
                }}
              />

              <Typography variant="h1" gutterBottom>
                Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
              </Typography>

              <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
                Enhance bland client feedback into compelling stories that showcase your true impact—with AI that captures transformation, emotion, and results.
              </Typography>

              <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                <Button 
                  variant="contained" 
                  color="primary"
                  size="large"
                  component={RouterLink}
                  to="/enhance"
                  endIcon={<ArrowForwardIcon />}
                  sx={{ py: 1.5, px: 3 }}
                >
                  Enhance a Testimonial
                </Button>

                <Button 
                  variant="outlined" 
                  color="primary"
                  size="large"
                  startIcon={<PlayArrowIcon />}
                  sx={{ py: 1.5, px: 3 }}
                >
                  See How It Works
                </Button>
              </Stack>

              <Box sx={{ display: 'flex', alignItems: 'center', mt: 4 }}>
                <Box sx={{ display: 'flex', mr: 1.5 }}>
                  {[1, 2, 3, 4, 5].map((star) => (
                    <StarIcon key={star} sx={{ color: '#FFD700', fontSize: 20 }} />
                  ))}
                </Box>
                <Typography variant="subtitle2" fontWeight={600}>
                  4.9/5
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ ml: 1 }}>
                  from 200+ users
                </Typography>
              </Box>
            </Grid>

            <Grid item xs={12} md={6}>
              {/* Testimonial Example Card */}
              <Box
                sx={{
                  position: 'relative',
                  height: { xs: 500, md: 550 },
                  width: '100%',
                  perspective: '1000px'
                }}
              >
                {examples.map((example, index) => (
                  <Fade 
                    key={index} 
                    in={currentExample === index} 
                    timeout={800}
                    style={{ 
                      position: 'absolute',
                      top: 0,
                      left: 0,
                      width: '100%',
                      height: '100%',
                      display: currentExample === index ? 'block' : 'none'
                    }}
                  >
                    <Box
                      sx={{
                        position: 'relative',
                        height: '100%',
                        width: '100%',
                        transformStyle: 'preserve-3d',
                        transform: 'rotateY(5deg) rotateX(5deg)',
                        transition: 'transform 0.5s ease'
                      }}
                    >
                      {/* Original Testimonial Card */}
                      <Card
                        elevation={0}
                        sx={{
                          position: 'absolute',
                          top: '10%',
                          left: '5%',
                          width: '70%',
                          height: '40%',
                          borderRadius: 3,
                          border: '1px solid rgba(0, 0, 0, 0.08)',
                          bgcolor: 'white',
                          p: 3,
                          zIndex: 1,
                          boxShadow: '0px 4px 20px rgba(0, 0, 0, 0.05)'
                        }}
                      >
                        <Typography 
                          variant="overline" 
                          color="text.secondary"
                          sx={{ 
                            display: 'block', 
                            mb: 1,
                            fontWeight: 600
                          }}
                        >
                          ORIGINAL TESTIMONIAL
                        </Typography>

                        <Typography 
                          variant="body1" 
                          color="text.primary"
                          sx={{ 
                            fontSize: '1.1rem',
                            fontStyle: 'italic',
                            mb: 2,
                            height: '80px',
                            overflow: 'hidden'
                          }}
                        >
                          "{example.original}"
                        </Typography>

                        <Box sx={{ mt: 'auto', display: 'flex', alignItems: 'center' }}>
                          <Avatar 
                            sx={{ 
                              bgcolor: 'grey.200',
                              color: 'text.secondary',
                              width: 32,
                              height: 32,
                              mr: 1
                            }}
                          >
                            {example.avatar}
                          </Avatar>
                          <Typography variant="body2" color="text.secondary">
                            Client
                          </Typography>
                        </Box>
                      </Card>

                      {/* Enhanced Testimonial Card */}
                      <Card
                        elevation={0}
                        sx={{
                          position: 'absolute',
                          top: '30%',
                          right: '5%',
                          width: '80%',
                          height: '60%',
                          borderRadius: 3,
                          background: 'linear-gradient(135deg, #5D5FEF 0%, #7879F1 100%)',
                          color: 'white',
                          p: 3,
                          zIndex: 2,
                          boxShadow: '0px 8px 30px rgba(93, 95, 239, 0.3)'
                        }}
                      >
                        <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                          <Chip
                            icon={<AutoAwesomeIcon />}
                            label="ENHANCED"
                            sx={{ 
                              bgcolor: 'rgba(255, 255, 255, 0.2)', 
                              color: 'white',
                              fontWeight: 600,
                              '& .MuiChip-icon': { color: 'white' }
                            }}
                          />
                        </Box>

                        <Typography 
                          variant="body1" 
                          sx={{ 
                            fontSize: '1.2rem',
                            fontWeight: 500,
                            mb: 3,
                            lineHeight: 1.6,
                            height: '200px',
                            overflow: 'hidden'
                          }}
                        >
                          "{example.enhanced}"
                        </Typography>

                        <Box sx={{ mt: 'auto', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                          <Box sx={{ display: 'flex', alignItems: 'center' }}>
                            <Avatar 
                              sx={{ 
                                bgcolor: 'rgba(255, 255, 255, 0.2)',
                                color: 'white',
                                width: 32,
                                height: 32,
                                mr: 1
                              }}
                            >
                              {example.avatar}
                            </Avatar>
                            <Typography variant="body2">
                              {example.client}
                            </Typography>
                          </Box>
                          <Chip 
                            label={example.industry} 
                            size="small"
                            sx={{ 
                              bgcolor: 'rgba(255, 255, 255, 0.2)', 
                              color: 'white',
                              fontWeight: 500
                            }}
                          />
                        </Box>
                      </Card>
                    </Box>
                  </Fade>
                ))}

                {/* Dots for navigation */}
                <Box 
                  sx={{ 
                    position: 'absolute', 
                    bottom: -30, 
                    left: '50%', 
                    transform: 'translateX(-50%)',
                    display: 'flex',
                    gap: 1
                  }}
                >
                  {examples.map((_, index) => (
                    <Box
                      key={index}
                      onClick={() => setCurrentExample(index)}
                      sx={{
                        width: 8,
                        height: 8,
                        borderRadius: '50%',
                        bgcolor: currentExample === index ? 'primary.main' : 'grey.300',
                        cursor: 'pointer',
                        transition: 'all 0.2s ease'
                      }}
                    />
                  ))}
                </Box>
              </Box>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* How It Works Section */}
      <Box sx={{ py: 10 }}>
        <Container maxWidth="lg">
          <Typography variant="h2" align="center" gutterBottom>
            How It Works
          </Typography>
          <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 8, maxWidth: 700, mx: 'auto' }}>
            Transform bland testimonials into powerful stories in three simple steps
          </Typography>

          <Grid container spacing={4}>
            <Grid item xs={12} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  1
                </Box>
                <Typography variant="h5" gutterBottom>
                  Submit raw testimonial
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Paste your client's original words, no matter how brief or bland they might be.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  2
                </Box>
                <Typography variant="h5" gutterBottom>
                  Get AI-enhanced version
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Our AI extracts the transformation, emotion, and impact from your client's experience.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  3
                </Box>
                <Typography variant="h5" gutterBottom>
                  One-click client approval
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Send a verification link to your client for instant approval with a single click.
                </Typography>
              </Card>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* CTA Section */}
      <Box sx={{ py: 10 }}>
        <Container maxWidth="md">
          <Card 
            sx={{ 
              p: { xs: 4, md: 6 },
              background: 'linear-gradient(135deg, #5D5FEF 0%, #7879F1 100%)',
              color: 'white',
              textAlign: 'center',
              position: 'relative',
              overflow: 'hidden',
              borderRadius: 4
            }}
          >
            <Box 
              sx={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                opacity: 0.1,
                backgroundImage: 'radial-gradient(circle, #ffffff 1px, transparent 1px)',
                backgroundSize: '20px 20px'
              }}
            />

            <Typography variant="h3" gutterBottom>
              Ready to transform your testimonials?
            </Typography>
            <Typography variant="subtitle1" sx={{ mb: 4, opacity: 0.9, maxWidth: 600, mx: 'auto' }}>
              Start free, no credit card required. Upgrade when you need more.
            </Typography>
            <Button 
              variant="contained" 
              size="large"
              component={RouterLink}
              to="/enhance"
              sx={{ 
                px: 4, 
                py: 1.5,
                bgcolor: 'white',
                color: 'primary.main',
                '&:hover': {
                  bgcolor: 'rgba(255, 255, 255, 0.9)'
                }
              }}
            >
              Get Started Now
            </Button>
          </Card>
        </Container>
      </Box>
    </Box>
  );
};

export default HomePage;
